#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(long long n, vector<long long> costs) {
    if (n == 0) return 0;

    vector<long long> dp(n + 1, LLONG_MAX);
    dp[0] = 0;

    for (long long i = 0; i <= n; ++i) {
        for (long long j = 1; j <= 3 && i + j <= n; ++j) {
            long long next = i + j;
            long long cost = costs[next - 1] + (j * j);
            if (dp[i] + cost < dp[next]) {
                dp[next] = dp[i] + cost;
            }
        }
    }

    return dp[n];
}
